   598→
   599→export function InfiniteCanvas({
   600→  zoom,
   601→  lod,
   602→  onZoomChange,
   603→  onViewportChange,
   604→  onMinZoomChange,
   605→  animatedZoomTarget,
   606→  onAnimatedZoomComplete,
   607→  navigationTarget,
   608→  onNavigationComplete,
   609→  perfVisible = false,
   610→  perfEvent = 'idle',
   611→}: InfiniteCanvasProps) {
   612→  const containerRef = useRef<HTMLDivElement>(null);
   613→
   614→  // ─────────────────────────────────────────────────────────────
   615→  // ARIA LIVE REGION STATE (F022)
   616→  // ─────────────────────────────────────────────────────────────
   617→  const ariaLiveRef = useRef<HTMLDivElement>(null);
   618→  const previousLodRef = useRef<LODLevel>(lod);
   619→  const previousZoomRef = useRef<number>(zoom);
   620→  const zoomAnnouncementTimeoutRef = useRef<number | null>(null);
   621→
   622→  // ─────────────────────────────────────────────────────────────
   623→  // STATE FROM CANVAS MACHINE (replaces useState)
   624→  // Using useSyncExternalStore under the hood - no stale closures!
   625→  // ─────────────────────────────────────────────────────────────
   626→  const isInitialized = useCanvasSelector((s) => s.viewport.isInitialized);
   627→  const canvasSize = useCanvasSelector((s) => s.viewport.canvasSize);
   628→  const cameraPos = useCanvasSelector((s) => s.viewport.camera);
   629→  const isPanning = useCanvasSelector((s) => s.viewport.isPanning);
   630→  const panStart = useCanvasSelector((s) => s.viewport.panStart);
   631→  const cameraPosAtPanStart = useCanvasSelector((s) => s.viewport.cameraPosAtPanStart);
   632→  const momentum = useCanvasSelector((s) => s.viewport.momentum);
   633→
   634→  // Interaction state (F018 hover, F019 selection)
   635→  const hoveredTaskId = useCanvasSelector((s) => s.interaction.hoveredTaskId);
   636→  const selectedTaskId = useCanvasSelector((s) => s.interaction.selectedTaskId);
   637→  const focusedTaskId = useCanvasSelector((s) => s.interaction.focusedTaskId);
   638→  const isHoverable = useCanvasSelector((s) => s.interaction.isHoverable);
   639→
   640→  // Get render data (memoized)
   641→  const { trains, tasks } = useMemo(() => getRenderData(), []);
   642→
   643→  // Calculate world bounds (for pan clamping)
   644→  const worldBounds = useMemo<WorldBounds>(() => {
   645→    const totalDays = 365 * 10; // 10 years
   646→    return calculateWorldBounds(trains.length, totalDays);
   647→  }, [trains.length]);
   648→
   649→  /**
   650→   * Calculate dynamic MIN_ZOOM to prevent white space around content.
   651→   * MIN_ZOOM is set so the viewport never exceeds the world bounds.
   652→   */
   653→  const effectiveMinZoom = useMemo(() => {
