  1756→        canvasSize.height,
  1757→        tasks
  1758→      );
  1759→
  1760→      // Only update if changed (avoid unnecessary state updates)
  1761→      if (taskId !== state.interaction.hoveredTaskId) {
  1762→        canvasStore.dispatch(canvasActions.interaction.setHoveredTask(taskId));
  1763→      }
  1764→    },
  1765→    [zoom, canvasSize, tasks]
  1766→  );
  1767→
  1768→  /**
  1769→   * Handle pan move / pinch move
  1770→   *
  1771→   * Now uses canvasStore for pan state - values always current
  1772→   */
  1773→  const handlePointerMove = useCallback(
  1774→    (e: React.PointerEvent) => {
  1775→      const pinch = pinchRef.current;
  1776→
  1777→      // Update pointer position
  1778→      if (pinch.pointers.has(e.pointerId)) {
  1779→        pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1780→      }
  1781→
  1782→      // Handle pinch gesture
  1783→      if (pinch.active && pinch.pointers.size === 2) {
  1784→        const pointers = Array.from(pinch.pointers.values());
  1785→        const dx = pointers[0].x - pointers[1].x;
  1786→        const dy = pointers[0].y - pointers[1].y;
  1787→        const currentDistance = Math.sqrt(dx * dx + dy * dy);
  1788→
  1789→        if (pinch.initialDistance > 0) {
  1790→          const scale = currentDistance / pinch.initialDistance;
  1791→          const centerX = (pointers[0].x + pointers[1].x) / 2;
  1792→          const centerY = (pointers[0].y + pointers[1].y) / 2;
  1793→          handlePinchZoom(scale, centerX, centerY);
  1794→        }
  1795→        return;
  1796→      }
  1797→
  1798→      // Update hover state (F018) - always run to update cursor
  1799→      updateHover(e);
  1800→
  1801→      // Handle pan - get current state from store
  1802→      const state = canvasStore.getState();
  1803→      if (!state.viewport.isPanning) return;
  1804→
  1805→      const dx = (e.clientX - state.viewport.panStart.x) / zoom;
  1806→      const dy = (e.clientY - state.viewport.panStart.y) / zoom;
  1807→
  1808→      // Detect significant movement (F019: to distinguish click from pan)
  1809→      // Using 8px threshold - movement greater than this is a pan, not a click
  1810→      // Higher threshold helps with touchpad/mouse precision issues
  1811→      const moveX = e.clientX - pointerDownPosRef.current.x;
  1812→      const moveY = e.clientY - pointerDownPosRef.current.y;
  1813→      const moveDistance = Math.sqrt(moveX * moveX + moveY * moveY);
  1814→      if (moveDistance > 8) {
  1815→        pointerMovedRef.current = true;
  1816→      }
  1817→
  1818→      const newX = state.viewport.cameraPosAtPanStart.x - dx;
  1819→      const newY = state.viewport.cameraPosAtPanStart.y + dy;
  1820→
  1821→      const clamped = clampCameraToWorld(newX, newY, zoom);
  1822→
  1823→      // Update pan in store
  1824→      canvasStore.dispatch(canvasActions.viewport.updatePan({ camera: clamped }));
  1825→      notifyViewportChange(clamped.x, clamped.y, zoom);
  1826→
  1827→      // Track velocity samples for momentum
  1828→      const now = performance.now();
  1829→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
  1830→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
  1831→
  1832→      velocitySamplesRef.current.push({
  1833→        x: worldDx,
  1834→        y: worldDy,
  1835→        time: now,
  1836→      });
  1837→
  1838→      // Keep only recent samples
  1839→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
  1840→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
  1841→      }
  1842→
  1843→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1844→    },
  1845→    [zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom, updateHover]
  1846→  );
  1847→
  1848→  /**
  1849→   * Handle pan end / pinch end
  1850→   *
  1851→   * Now uses canvasStore for pan state
  1852→   */
  1853→  const handlePointerUp = useCallback(
  1854→    (e: React.PointerEvent) => {
  1855→      const pinch = pinchRef.current;
  1856→
  1857→      // Remove pointer from tracking
  1858→      pinch.pointers.delete(e.pointerId);
  1859→
  1860→      // Release pointer capture
  1861→      try {
  1862→        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  1863→      } catch {
  1864→        // Ignore if capture was already released
  1865→      }
  1866→
  1867→      // Reset pinch state when all pointers released
  1868→      if (pinch.pointers.size < 2) {
  1869→        pinch.active = false;
  1870→        pinch.initialDistance = 0;
  1871→      }
  1872→
  1873→      // Handle pan end with momentum - check store for isPanning
  1874→      const state = canvasStore.getState();
  1875→      if (state.viewport.isPanning && pinch.pointers.size === 0) {
  1876→        canvasStore.dispatch(canvasActions.viewport.endPan());
  1877→
  1878→        // BUG-008: Momentum disabled - was causing elastic/jumping behavior
  1879→        // The momentum animation had stale closure issues despite the cameraPosRef fix
  1880→        // TODO: Reimplement with proper state synchronization if momentum UX is desired
  1881→        // Original code:
  1882→        // const { vx, vy } = calculateAverageVelocity();
  1883→        // const speed = Math.sqrt(vx ** 2 + vy ** 2);
  1884→        // if (speed > 0.01) { startMomentum(vx, vy); }
  1885→      }
  1886→    },
  1887→    [calculateAverageVelocity, startMomentum]
  1888→  );
  1889→
  1890→  /**
  1891→   * Handle double-click to zoom in at click location
  1892→   * Zooms 2x toward the clicked point with smooth animation
  1893→   *
  1894→   * Now uses animateZoomTo which uses the canvasStore
  1895→   */
  1896→  const handleDoubleClick = useCallback(
  1897→    (e: React.MouseEvent) => {
  1898→      if (!isInitialized) return;
  1899→
  1900→      // Stop any active animations
  1901→      stopMomentum();
  1902→      stopZoomAnimation();
  1903→
  1904→      const rect = containerRef.current?.getBoundingClientRect();
  1905→      if (!rect) return;
  1906→
  1907→      // Get current camera from store
  1908→      const currentCamera = canvasStore.getState().viewport.camera;
  1909→
  1910→      // Calculate target zoom (2x, clamped to MAX_ZOOM)
  1911→      const targetZoom = Math.min(zoom * 2, MAX_ZOOM);
  1912→      if (Math.abs(targetZoom - zoom) < 0.001) return;
  1913→
  1914→      // Cursor position relative to canvas center
  1915→      const cursorX = e.clientX - rect.left - rect.width / 2;
  1916→      const cursorY = e.clientY - rect.top - rect.height / 2;
  1917→
  1918→      // Calculate target camera position (zoom toward click point)
  1919→      const worldX = cursorX / zoom + currentCamera.x;
  1920→      const worldY = -cursorY / zoom + currentCamera.y;
  1921→      const newCameraX = worldX - cursorX / targetZoom;
  1922→      const newCameraY = worldY + cursorY / targetZoom;
  1923→
  1924→      const clamped = clampCameraToWorld(newCameraX, newCameraY, targetZoom);
  1925→
  1926→      // Animate with slightly longer duration for double-click (350ms)
  1927→      animateZoomTo(targetZoom, clamped.x, clamped.y, 350);
  1928→    },
  1929→    [zoom, isInitialized, stopMomentum, stopZoomAnimation, clampCameraToWorld, animateZoomTo]
  1930→  );
  1931→
  1932→  /**
  1933→   * Handle click to select/deselect task (F019)
  1934→   * Clicks on tasks select them, clicks on background deselect
  1935→   */
  1936→  const handleClick = useCallback(
  1937→    (e: React.MouseEvent) => {
  1938→      if (!isInitialized) return;
  1939→
  1940→      // Don't process clicks that are part of a pan gesture
  1941→      // If pointer moved significantly between down and up, this is a pan, not a click
  1942→      if (pointerMovedRef.current) {
  1943→        return;
  1944→      }
  1945→
  1946→      const state = canvasStore.getState();
  1947→
  1948→      const container = containerRef.current;
  1949→      if (!container) return;
  1950→
  1951→      const rect = container.getBoundingClientRect();
  1952→      const camera = state.viewport.camera;
  1953→
  1954→      // Find task at click position
  1955→      const taskId = findTaskAtPosition(
  1956→        e.clientX,
  1957→        e.clientY,
  1958→        rect,
  1959→        camera.x,
  1960→        camera.y,
  1961→        zoom,
  1962→        canvasSize.width,
  1963→        canvasSize.height,
  1964→        tasks
  1965→      );
  1966→
  1967→      if (taskId) {
  1968→        // Toggle selection: if clicking same task, deselect; otherwise, select
  1969→        if (taskId === state.interaction.selectedTaskId) {
  1970→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1971→        } else {
  1972→          canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
  1973→        }
  1974→      } else {
  1975→        // Clicked on background: clear selection
  1976→        if (state.interaction.selectedTaskId !== null) {
  1977→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1978→        }
  1979→      }
  1980→    },
  1981→    [isInitialized, zoom, canvasSize, tasks]
  1982→  );
  1983→
  1984→  /**
  1985→   * Handle pointer leave - clear pan and hover state
  1986→   */
  1987→  const handlePointerLeave = useCallback(
  1988→    (e: React.PointerEvent) => {
  1989→      // Handle pan end
  1990→      handlePointerUp(e);
  1991→      // Clear hover state (F018)
  1992→      canvasStore.dispatch(canvasActions.interaction.clearHover());
  1993→    },
  1994→    [handlePointerUp]
  1995→  );
  1996→
  1997→  // Determine cursor style: grabbing when panning, pointer when hovering task, grab otherwise
  1998→  const cursorStyle = isPanning ? 'grabbing' : isHoverable ? 'pointer' : 'grab';
  1999→
  2000→  // Generate aria-label with current state information (F022)
  2001→  const ariaLabel = `Metro maintenance planning canvas. ${LOD_LABELS[lod]}. ${formatZoomForAria(zoom)}. Use Tab to navigate tasks, Enter to select, Arrow keys to pan, plus minus to zoom.`;
  2002→
  2003→  return (
  2004→    <div
  2005→      ref={containerRef}
  2006→      // F022: ARIA attributes for accessibility
  2007→      role="application"
  2008→      aria-label={ariaLabel}
  2009→      aria-roledescription="Interactive maintenance scheduling canvas"
  2010→      style={{
  2011→        width: '100%',
  2012→        height: '100%',
  2013→        cursor: cursorStyle,
  2014→        touchAction: 'none',
  2015→        position: 'relative', // For absolute positioning of live region
  2016→      }}
  2017→      onPointerDown={handlePointerDown}
  2018→      onPointerMove={handlePointerMove}
  2019→      onPointerUp={handlePointerUp}
  2020→      onPointerLeave={handlePointerLeave}
  2021→      onDoubleClick={handleDoubleClick}
  2022→      onClick={handleClick}
  2023→    >
  2024→      {/* F022: ARIA Live Region for screen reader announcements */}
  2025→      <div
  2026→        ref={ariaLiveRef}
  2027→        role="status"
  2028→        aria-live="polite"
  2029→        aria-atomic="true"
  2030→        style={{
  2031→          position: 'absolute',
  2032→          width: '1px',
  2033→          height: '1px',
  2034→          padding: '0',
  2035→          margin: '-1px',
  2036→          overflow: 'hidden',
  2037→          clip: 'rect(0, 0, 0, 0)',
  2038→          whiteSpace: 'nowrap',
  2039→          border: '0',
  2040→        }}
  2041→      />
  2042→      <Canvas
  2043→        gl={{ antialias: true, alpha: false }}
  2044→        style={{ background: '#f4f4f5' }}
  2045→        orthographic
  2046→        camera={{
  2047→          position: [cameraPos.x, cameraPos.y, 100],
  2048→          zoom: zoom,
  2049→          near: 0.1,
  2050→          far: 1000,
  2051→        }}
  2052→      >
  2053→        <CameraController
  2054→          cameraX={cameraPos.x}
  2055→          cameraY={cameraPos.y}
  2056→          zoom={zoom}
  2057→          worldBounds={worldBounds}
  2058→          isInitialized={isInitialized}
  2059→          onInitialized={handleCameraInitialized}
  2060→          onViewportChange={onViewportChange}
  2061→        />
  2062→
  2063→        <color attach="background" args={['#f4f4f5']} />
  2064→
  2065→        {/* LOD-based layer rendering with smooth transitions */}
  2066→        <LODLayers
  2067→          tasks={tasks}
  2068→          trainCount={trains.length}
  2069→          zoom={zoom}
  2070→          viewportBounds={viewportBounds}
